				content: [{ type: "text", text: lastText || "(running...)" }],
				details: {
					mode: "single",
					items: [{
						thread: threadName,
						action,
						episode: "(running...)",
						episodeNumber,
						result,
					}],
				},
			});
		}
	};

	// Write thread worker prompt to temp file
	const promptTmp = writeTempFile("worker", THREAD_WORKER_PROMPT);

	try {

