		// Single process: thread executes the action AND produces the episode
		// inline (delimited by ---EPISODE--- markers). No second process needed.
		const actionResult = await runPiOnThread(
			cwd,
			sessionPath,
			action,
			model,
			promptTmp.filePath,
			signal,
			(msg) => {
				result.messages.push(msg);
				trackUsage(msg);
				emitUpdate();
